+    payload: {
+      kind: "systemEvent",
+      text: "Morning brief",
+    },
+    state: {},
+    ...overrides,
+  };
+}
+
+async function writeCronStore(storePath: string, jobs: Array<Record<string, unknown>>) {
+  await fs.mkdir(path.dirname(storePath), { recursive: true });
+  await fs.writeFile(
+    storePath,
+    JSON.stringify(
+      {
+        version: 1,
+        jobs,
+      },
+      null,
+      2,
+    ),
+    "utf-8",
+  );
+}
